refentry.refsect1:
&reftitle.description;
mixedarray_find arrayarray callablecallback
array_find gibt den Wert des ersten Elements eines &array;s zurück, für das die übergebene callback-Funktion &true; zurückgibt. Wenn kein passendes Element gefunden wird, gibt die Funktion &null; zurück.

  &reftitle.examples;

   array_find-Beispiel


<?php
$array = [
    'a' => 'dog',
    'b' => 'cat',
    'c' => 'cow',
    'd' => 'duck',
    'e' => 'goose',
    'f' => 'elephant'
];

// Findet das erste Tier mit einem Namen, der länger als 4 Zeichen ist.
var_dump(array_find($array, function (string $value) {
    return strlen($value) > 4;
}));

// Findet das erste Tier, dessen Name mit f beginnt.
var_dump(array_find($array, function (string $value) {
    return str_starts_with($value, 'f');
}));

// Findet das erste Tier, bei dem der Array-Schlüssel das erste Zeichen des Tiernamens ist.
var_dump(array_find($array, function (string $value, $key) {
   return $value[0] === $key;
}));

// Findet das erste Tier, bei dem der Array-Schlüssel einem regulären Ausdruck entspricht.
var_dump(array_find($array, function ($value, $key) {
   return preg_match('/^([a-f])$/', $key);
}));
?>


   &example.outputs;


string(5) "goose"
NULL
string(3) "cow"
string(3) "dog"
